import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;

public class SecureDataEncryptor {

    private static final String ALGORITHM = "AES";
    private static final int KEY_SIZE = 256; // in bits
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";

    public static byte[] generateKey() throws NoSuchAlgorithmException {
        KeyGenerator keyGen = KeyGenerator.getInstance(ALGORITHM);
        keyGen.init(KEY_SIZE, new SecureRandom());
        SecretKey secretKey = keyGen.generateKey();
        return secretKey.getEncoded();
    }

    public static String encrypt(byte[] data, byte[] key) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        SecretKeySpec secretKeySpec = new SecretKeySpec(key, ALGORITHM);
        cipher.init(Cipher.ENCRYPT_MODE, secretKeySpec);
        byte[] encryptedData = cipher.doFinal(data);
        return Base64.getEncoder().encodeToString(encryptedData);
    }

    public static byte[] decrypt(String encryptedData, byte[] key) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        SecretKeySpec secretKeySpec = new SecretKeySpec(key, ALGORITHM);
        cipher.init(Cipher.DECRYPT_MODE, secretKeySpec);
        byte[] decodedBytes = Base64.getDecoder().decode(encryptedData);
        return cipher.doFinal(decodedBytes);
    }

    public static void main(String[] args) throws Exception {
        // Generate a key
        byte[] key = generateKey();

        // Encrypt some data
        String data = "Sensitive user data";
        byte[] encryptedData = encrypt(data.getBytes(), key);

        // Decrypt the data
        String decryptedData = new String(decrypt(Base64.getEncoder().encodeToString(encryptedData), key));

        System.out.println("Decrypted Data: " + decryptedData);
    }
}